patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..027378f77c19 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1326,7 +1326,6 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   if (!match(ICmp1, m_ICmp(Pred1, m_Value(V1), m_APInt(C1))) ||
       !match(ICmp2, m_ICmp(Pred2, m_Value(V2), m_APInt(C2))))
     return nullptr;
-
   // Look through add of a constant offset on V1, V2, or both operands. This
   // allows us to interpret the V + C' < C'' range idiom into a proper range.
   const APInt *Offset1 = nullptr, *Offset2 = nullptr;
@@ -1338,16 +1337,48 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
   }

+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
+  bool UseMask1 = false, UseMask2 = false;
+  if (V1 != V2 && IsAnd != ICmpInst::isTrueWhenEqual(Pred1) &&
+      IsAnd != ICmpInst::isTrueWhenEqual(Pred2)) {
+    Value *X;
+    UseMask1 = ICmpInst::isEquality(Pred1) && ICmp1->hasOneUse() &&
+               match(V1, m_And(m_Value(X), m_APInt(Mask1)));
+    if (UseMask1)
+      V1 = X;
+    UseMask2 = ICmpInst::isEquality(Pred2) && ICmp2->hasOneUse() &&
+               match(V2, m_And(m_Value(X), m_APInt(Mask2)));
+    if (UseMask2)
+      V2 = X;
+  }
+  }
+
   if (V1 != V2)
     return nullptr;

-  ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
+  auto GetRangeForCmp = [&](CmpPredicate Pred, const APInt &C,
+                            const APInt *Mask) -> ConstantRange {
+    if (!Mask)
+      return ConstantRange::makeExactICmpRegion(Pred, C);
+
+    if (!ICmpInst::isEquality(Pred) || C.intersects(~*Mask))
+      return ConstantRange::getFull(C.getBitWidth());
+
+    APInt InvMask = ~*Mask;
+    return Pred == ICmpInst::ICMP_EQ
+               ? ConstantRange(C, (C + InvMask + 1))
+               : ConstantRange(C + InvMask + 1, C);
+  };
+
+  ConstantRange CR1 = GetRangeForCmp(
+      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1,
+      UseMask1 ? Mask1 : nullptr);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);

-  ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
-      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
+  ConstantRange CR2 = GetRangeForCmp(
+      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2,
+      UseMask2 ? Mask2 : nullptr);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);

